// client/hooks/useQueryParam.ts
import { useSyncExternalStore, useCallback } from 'react';
import { ZodSchema } from 'zod';
function subscribe(cb: () => void) {
  window.addEventListener('popstate', cb);
  return () => window.removeEventListener('popstate', cb);
}
export function useQueryParam<T>(key: string, schema: ZodSchema<T>, opts: { replace?: boolean } = {}): [T | undefined, (v: T | undefined) => void] {
  const get = useCallback(() => new URLSearchParams(window.location.search).get(key), [key]);
  const raw = useSyncExternalStore(subscribe, get, () => null);
  const value = raw === null ? undefined : (() => { const p = schema.safeParse(raw); return p.success ? p.data : undefined; })();
  const setValue = useCallback((v: T | undefined) => {
    const url = new URL(window.location.href);
    if (v === undefined) url.searchParams.delete(key);
    else url.searchParams.set(key, String(v));
    const method = opts.replace ? 'replaceState' : 'pushState';
    window.history[method]({}, '', url);
    window.dispatchEvent(new PopStateEvent('popstate'));
  }, [key, opts.replace]);
  return [value, setValue];
}

// client/hooks/useScript.ts
import { useEffect, useState } from 'react';
type Status = 'idle' | 'loading' | 'ready' | 'error';
const cache = new Map<string, { promise: Promise<void>; status: Status }>();
export function useScript(src: string | null): Status {
  const [status, setStatus] = useState<Status>(src ? (cache.get(src)?.status ?? 'loading') : 'idle');
  useEffect(() => {
    if (!src) { setStatus('idle'); return; }
    const existing = cache.get(src);
    if (existing) {
      existing.promise.then(() => setStatus(cache.get(src)!.status));
      return;
    }
    const script = document.createElement('script');
    script.src = src; script.async = true;
    const promise = new Promise<void>((resolve, reject) => {
      script.onload = () => { cache.set(src, { promise, status: 'ready' }); resolve(); };
      script.onerror = () => { cache.set(src, { promise, status: 'error' }); reject(); };
    });
    cache.set(src, { promise, status: 'loading' });
    document.head.appendChild(script);
    promise.then(() => setStatus('ready')).catch(() => setStatus('error'));
  }, [src]);
  return status;
}

// client/hooks/useCopyToClipboard.ts
import { useState, useCallback, useRef, useEffect } from 'react';
export function useCopyToClipboard(resetMs = 2000) {
  const [copied, setCopied] = useState(false);
  const timerRef = useRef<number | null>(null);
  const copy = useCallback(async (text: string) => {
    try {
      await navigator.clipboard.writeText(text);
      setCopied(true);
      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = window.setTimeout(() => setCopied(false), resetMs);
      return true;
    } catch { return false; }
  }, [resetMs]);
  useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);
  return { copied, copy };
}

// client/hooks/useInfiniteList.ts
import { useCallback, useEffect, useState } from 'react';
import { useIntersection } from './useIntersection';
export function useInfiniteList<T>(fetchPage: (cursor: string | null) => Promise<{ items: T[]; nextCursor: string | null }>) {
  const [items, setItems] = useState<T[]>([]);
  const [cursor, setCursor] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [done, setDone] = useState(false);
  const [sentinelRef, visible] = useIntersection<HTMLDivElement>({ rootMargin: '100px' });
  const loadMore = useCallback(async () => {
    if (loading || done) return;
    setLoading(true);
    try {
      const r = await fetchPage(cursor);
      setItems(prev => [...prev, ...r.items]);
      setCursor(r.nextCursor);
      if (!r.nextCursor) setDone(true);
    } finally { setLoading(false); }
  }, [cursor, loading, done, fetchPage]);
  useEffect(() => { if (visible) loadMore(); }, [visible]);
  useEffect(() => { loadMore(); }, []); // initial
  return { items, sentinelRef, loading, done };
}

