// server/lib/circuitBreaker.ts
export class CircuitBreaker {
  private failures = 0;
  private state: 'closed' | 'open' | 'halfOpen' = 'closed';
  private nextAttempt = 0;
  constructor(private opts: { threshold: number; timeoutMs: number; resetMs: number; name: string }) {}
  async call<T>(fn: () => Promise<T>): Promise<T> {
    if (this.state === 'open') {
      if (Date.now() < this.nextAttempt) throw new Error(`Circuit ${this.opts.name} open`);
      this.state = 'halfOpen';
    }
    try {
      const result = await Promise.race([fn(), new Promise<never>((_, rej) => setTimeout(() => rej(new Error('timeout')), this.opts.timeoutMs))]);
      this.failures = 0;
      this.state = 'closed';
      return result;
    } catch (e) {
      this.failures++;
      if (this.failures >= this.opts.threshold) {
        this.state = 'open';
        this.nextAttempt = Date.now() + this.opts.resetMs;
      }
      throw e;
    }
  }
}
export const stripeBreaker = new CircuitBreaker({ threshold: 5, timeoutMs: 3000, resetMs: 30000, name: 'stripe' });

