// client/context/BannerStack.tsx
import { createContext, useContext, useState, useEffect } from 'react';
type Banner = { id: string; severity: 'info'|'warning'|'error'; render: () => React.ReactNode; dismissible?: boolean; version?: number };
const Ctx = createContext<{ register: (b: Banner) => void; deregister: (id: string) => void } | null>(null);
export function BannerStackProvider({ children }: { children: React.ReactNode }) {
  const [banners, setBanners] = useState<Banner[]>([]);
  const [dismissed, setDismissed] = useState<Record<string, number>>(() => JSON.parse(localStorage.getItem('dismissedBanners') ?? '{}'));
  const register = (b: Banner) => setBanners(prev => prev.find(x => x.id === b.id) ? prev : [...prev, b]);
  const deregister = (id: string) => setBanners(prev => prev.filter(b => b.id !== id));
  const visible = banners
    .filter(b => (dismissed[b.id] ?? -1) < (b.version ?? 0))
    .sort((a, b) => priorityOf(b.severity) - priorityOf(a.severity))
    .slice(0, 1);
  const dismiss = (id: string, version = 0) => { const next = { ...dismissed, [id]: version }; setDismissed(next); localStorage.setItem('dismissedBanners', JSON.stringify(next)); };
  return <Ctx.Provider value={{ register, deregister }}>{visible.map(b => <div key={b.id}>{b.render()}{b.dismissible && <button onClick={() => dismiss(b.id, b.version)}>Dismiss</button>}</div>)}{children}</Ctx.Provider>;
}
function priorityOf(s: string) { return s === 'error' ? 3 : s === 'warning' ? 2 : 1; }

