// server/middleware/apiKey.ts
import { RequestHandler } from 'express';
import { createHash } from 'crypto';
import { ApiKeyModel } from '../models/ApiKey';
export const requireScope = (scope: string): RequestHandler => async (req, res, next) => {
  const header = req.header('authorization')?.replace('Bearer ', '');
  if (!header) return next(new UnauthorizedError('No API key'));
  const hash = createHash('sha256').update(header).digest('hex');
  const key = await ApiKeyModel.findOne({ hash });
  if (!key || key.revokedAt || (key.expiresAt && key.expiresAt < new Date())) return next(new UnauthorizedError('Invalid API key'));
  if (!key.scopes.includes(scope) && !key.scopes.includes('*')) return next(new ForbiddenError(`Scope ${scope} required`));
  await ApiKeyModel.updateOne({ _id: key._id }, { lastUsedAt: new Date() });
  (req as any).user = { tenantId: key.tenantId, apiKeyId: key._id };
  next();
};

