import { bin } from 'd3-array';
import { scaleLinear } from '@visx/scale';
import { Bar } from '@visx/shape';
import { Group } from '@visx/group';
import { AxisBottom, AxisLeft } from '@visx/axis';
import { useMemo } from 'react';
export function Histogram({ values, width, height }: { values: number[]; width: number; height: number }) {
  const bins = useMemo(() => bin().thresholds(20)(values), [values]);
  const x = scaleLinear({ range: [40, width - 10], domain: [bins[0].x0!, bins[bins.length - 1].x1!] });
  const y = scaleLinear({ range: [height - 30, 10], domain: [0, Math.max(...bins.map(b => b.length))] });
  return (
    <svg width={width} height={height}>
      <Group>{bins.map((b, i) => <Bar key={i} x={x(b.x0!)} y={y(b.length)} width={x(b.x1!) - x(b.x0!) - 1} height={height - 30 - y(b.length)} fill="steelblue" />)}</Group>
      <AxisBottom scale={x} top={height - 30} />
      <AxisLeft scale={y} left={40} />
    </svg>
  );
}

