// server/services/provisioningService.ts
export const provisioningService = {
  async provision(input: any) {
    const tx = await ProvisioningModel.create({ status: 'reserving', input });
    try {
      const user = await userService.create(input);
      tx.userId = user.id; tx.status = 'user_created'; await tx.save();
      const ws = await workspaceService.create(user.id);
      tx.workspaceId = ws.id; tx.status = 'workspace_created'; await tx.save();
      const billing = await billingService.createCustomer(user);
      tx.billingId = billing.id; tx.status = 'completed'; await tx.save();
      return { user, ws, billing };
    } catch (e) {
      await this.rollback(tx);
      throw e;
    }
  },
  async rollback(tx: any) {
    if (tx.billingId) await billingService.deleteCustomer(tx.billingId);
    if (tx.workspaceId) await workspaceService.delete(tx.workspaceId);
    if (tx.userId) await userService.delete(tx.userId);
    tx.status = 'rolled_back'; await tx.save();
  }
};

// server/services/webhookDeliveryService.ts
import { createHmac } from 'crypto';
export const webhookDelivery = {
  async deliver(sub: any, event: any, attempt = 0): Promise<void> {
    const body = JSON.stringify(event);
    const sig = createHmac('sha256', sub.signingSecret).update(body).digest('hex');
    try {
      const r = await fetch(sub.url, { method: 'POST', headers: { 'content-type': 'application/json', 'x-signature': sig, 'x-event-id': event.id }, body });
      if (!r.ok) throw new Error(`${r.status}`);
      await WebhookDeliveryLog.create({ subId: sub.id, eventId: event.id, status: 'delivered', attempt });
    } catch (e) {
      if (attempt < 5) await scheduleRetry(sub, event, attempt + 1, Math.pow(2, attempt) * 1000);
      else await deadLetter.add({ subId: sub.id, event, error: String(e) });
    }
  }
};

