// server/services/slugService.ts
const RESERVED = new Set(['admin','api','auth','login','logout','signup','www','app','support','help','status']);
export const slugService = {
  base(name: string) { return name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 60); },
  async generate(name: string): Promise<string> {
    const base = this.base(name);
    if (RESERVED.has(base)) return this.generate(`${name} workspace`);
    for (let i = 0; i < 100; i++) {
      const candidate = i === 0 ? base : `${base}-${i + 1}`;
      if (await this.isAvailable(candidate)) return candidate;
    }
    return `${base}-${crypto.randomBytes(4).toString('hex')}`;
  },
  async isAvailable(slug: string): Promise<boolean> {
    if (RESERVED.has(slug)) return false;
    return !(await WorkspaceModel.exists({ slug }));
  }
};

