import { useEffect, useState } from 'react';
import { useDebounce } from '../hooks/useDebounce';
export function SlugInput({ name }: { name: string }) {
  const [slug, setSlug] = useState('');
  const [debSlug] = useDebounce(slug, { delay: 300 });
  const [status, setStatus] = useState<'idle'|'checking'|'available'|'taken'>('idle');
  useEffect(() => { if (!debSlug) return; setStatus('checking'); fetch(`/api/slug/check?slug=${debSlug}`).then(r => r.json()).then(s => setStatus(s.available ? 'available' : 'taken')); }, [debSlug]);
  return <div><input value={slug} onChange={e => setSlug(e.target.value)} /><span>{status === 'available' ? '✓' : status === 'taken' ? '✗' : ''}</span></div>;
}

